<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Falling Sand Sandbox</title>
<style>
  * { box-sizing: border-box; user-select: none; }
  body {
    margin: 0;
    background: #0d0d0d;
    color: #e0e0e0;
    font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 100vh;
  }
  .container {
    text-align: center;
    padding: 16px;
  }
  h1 {
    margin: 0 0 14px 0;
    font-weight: 300;
    letter-spacing: 1.5px;
    font-size: 1.6rem;
  }
  canvas#sand {
    width: 600px;
    height: 600px;
    max-width: 90vw;
    max-height: 65vh;
    image-rendering: pixelated;
    background: #111;
    border: 2px solid #333;
    border-radius: 8px;
    box-shadow: 0 12px 40px rgba(0,0,0,0.7);
    cursor: crosshair;
  }
  .controls {
    margin-top: 16px;
    display: flex;
    flex-direction: column;
    gap: 12px;
    align-items: center;
  }
  .materials {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
    justify-content: center;
  }
  button {
    border: none;
    padding: 10px 18px;
    border-radius: 6px;
    font-size: 14px;
    font-weight: 600;
    cursor: pointer;
    background: #222;
    color: #ddd;
    box-shadow: 0 2px 5px rgba(0,0,0,0.4);
    transition: transform .05s, background .15s, box-shadow .15s;
  }
  button:hover { background: #333; }
  button:active { transform: translateY(1px); }
  button.active {
    outline: 2px solid #fff;
    box-shadow: 0 0 10px rgba(255,255,255,0.15);
  }
  #mat-sand.active { background: #8d6e3c; color: #fff; }
  #mat-water.active { background: #1f618d; color: #fff; }
  #mat-wall.active { background: #555; color: #fff; }
  #mat-acid.active { background: #1e8449; color: #fff; }
  #mat-empty.active { background: #922b21; color: #fff; }
  #clear { background: #c0392b; color: #fff; }
  #clear:hover { background: #e74c3c; }
  .hint { font-size: 12px; color: #777; margin-top: 4px; }
</style>
</head>
<body>
<div class="container">
  <h1>Falling Sand Sandbox</h1>
  <canvas id="sand" width="120" height="120"></canvas>
  <div class="controls">
    <div class="materials">
      <button id="mat-sand" class="mat-btn active" data-mat="sand">Sand</button>
      <button id="mat-water" class="mat-btn" data-mat="water">Water</button>
      <button id="mat-wall" class="mat-btn" data-mat="wall">Wall</button>
      <button id="mat-acid" class="mat-btn" data-mat="acid">Acid</button>
      <button id="mat-empty" class="mat-btn" data-mat="empty">Eraser</button>
    </div>
    <button id="clear">Clear</button>
    <div class="hint">Drag on the canvas to paint with the selected material.</div>
  </div>
</div>

<script>
(function(){
  const W = 120, H = 120;
  const EMPTY = 0, SAND = 1, WATER = 2, WALL = 3, ACID = 4;
  const names = ['empty','sand','water','wall','acid'];
  const nameToId = {empty:0, sand:1, water:2, wall:3, acid:4};

  const grid = new Uint8Array(W * H);
  const moved = new Uint8Array(W * H);
  const colOrder = new Int16Array(W);

  let rngSeed = 123456789;
  function rand(){
    rngSeed = (rngSeed * 1664525 + 1013904223) | 0;
    return (rngSeed >>> 0) / 4294967296;
  }
  function randInt(n){ return (rand() * n) | 0; }

  function I(x, y){ return y * W + x; }
  function inBounds(x, y){ return x >= 0 && x < W && y >= 0 && y < H; }

  function moveTo(x, y, nx, ny){
    const i = I(x, y), j = I(nx, ny);
    grid[j] = grid[i];
    grid[i] = EMPTY;
    moved[i] = 1;
    moved[j] = 1;
  }

  function swap(x1, y1, x2, y2){
    const i = I(x1, y1), j = I(x2, y2);
    const t = grid[i];
    grid[i] = grid[j];
    grid[j] = t;
    moved[i] = 1;
    moved[j] = 1;
  }

  function tryMoveSand(x, y, nx, ny){
    const target = grid[I(nx, ny)];
    if(target === EMPTY){
      moveTo(x, y, nx, ny);
      return true;
    }
    if(target === WATER || target === ACID){
      const first = randInt(2);
      for(let k = 0; k < 2; k++){
        const dx = ((first + k) & 1) ? 1 : -1;
        const sx = x + dx;
        if(sx >= 0 && sx < W && grid[I(sx, y)] === EMPTY){
          const i = I(x, y), j = I(nx, ny), s = I(sx, y);
          grid[j] = SAND;
          grid[i] = EMPTY;
          grid[s] = target;
          moved[i] = 1;
          moved[j] = 1;
          moved[s] = 1;
          return true;
        }
      }
      swap(x, y, nx, ny);
      return true;
    }
    return false;
  }

  function updateSand(x, y){
    if(y + 1 >= H) return;
    const below = grid[I(x, y + 1)];
    if(below === EMPTY || below === WATER || below === ACID){
      if(tryMoveSand(x, y, x, y + 1)) return;
    }
    const first = randInt(2);
    for(let k = 0; k < 2; k++){
      const dx = ((first + k) & 1) ? 1 : -1;
      const nx = x + dx, ny = y + 1;
      if(nx >= 0 && nx < W){
        const t = grid[I(nx, ny)];
        if(t === EMPTY || t === WATER || t === ACID){
          if(tryMoveSand(x, y, nx, ny)) return;
        }
      }
    }
  }

  function updateWater(x, y){
    if(y + 1 < H && grid[I(x, y + 1)] === EMPTY){
      moveTo(x, y, x, y + 1);
      return;
    }
    const first = randInt(2);
    for(let k = 0; k < 2; k++){
      const dx = ((first + k) & 1) ? 1 : -1;
      const nx = x + dx, ny = y + 1;
      if(nx >= 0 && nx < W && ny < H && grid[I(nx, ny)] === EMPTY){
        moveTo(x, y, nx, ny);
        return;
      }
    }
    const firstH = randInt(2);
    for(let k = 0; k < 2; k++){
      const dx = ((firstH + k) & 1) ? 1 : -1;
      const nx = x + dx;
      if(nx >= 0 && nx < W && grid[I(nx, y)] === EMPTY){
        moveTo(x, y, nx, y);
        return;
      }
    }
  }

  function dissolve(x, y, nx, ny){
    const i = I(x, y), j = I(nx, ny);
    grid[j] = EMPTY;
    moved[i] = 1;
    moved[j] = 1;
  }

  function updateAcid(x, y){
    if(y + 1 < H){
      const below = grid[I(x, y + 1)];
      if(below === SAND || below === WALL){
        dissolve(x, y, x, y + 1);
        return;
      }
      if(below === EMPTY){
        moveTo(x, y, x, y + 1);
        return;
      }
    }
    const first = randInt(2);
    for(let k = 0; k < 2; k++){
      const dx = ((first + k) & 1) ? 1 : -1;
      const nx = x + dx;
      if(nx >= 0 && nx < W){
        const nb = grid[I(nx, y)];
        if(nb === SAND || nb === WALL){
          dissolve(x, y, nx, y);
          return;
        }
      }
    }
    const firstH = randInt(2);
    for(let k = 0; k < 2; k++){
      const dx = ((firstH + k) & 1) ? 1 : -1;
      const nx = x + dx;
      if(nx >= 0 && nx < W && grid[I(nx, y)] === EMPTY){
        moveTo(x, y, nx, y);
        return;
      }
    }
  }

  function step(){
    moved.fill(0);
    for(let y = H - 1; y >= 0; y--){
      for(let i = 0; i < W; i++) colOrder[i] = i;
      for(let i = W - 1; i > 0; i--){
        const j = randInt(i + 1);
        const t = colOrder[i];
        colOrder[i] = colOrder[j];
        colOrder[j] = t;
      }
      for(let xi = 0; xi < W; xi++){
        const x = colOrder[xi];
        const i = I(x, y);
        if(moved[i]) continue;
        const m = grid[i];
        if(m === SAND) updateSand(x, y);
        else if(m === WATER) updateWater(x, y);
        else if(m === ACID) updateAcid(x, y);
      }
    }
  }

  const canvas = document.getElementById('sand');
  const ctx = canvas.getContext('2d', { alpha: false });
  const imgData = ctx.createImageData(W, H);
  const buf = imgData.data;
  const colors = [
    [20, 20, 20, 255],
    [230, 194, 136, 255],
    [52, 152, 219, 255],
    [127, 140, 141, 255],
    [57, 255, 20, 255]
  ];

  function render(){
    for(let i = 0; i < W * H; i++){
      const c = colors[grid[i]];
      const p = i * 4;
      buf[p] = c[0];
      buf[p + 1] = c[1];
      buf[p + 2] = c[2];
      buf[p + 3] = c[3];
    }
    ctx.putImageData(imgData, 0, 0);
  }

  let selectedMat = SAND;
  let drawing = false;

  const matButtons = document.querySelectorAll('.mat-btn');
  matButtons.forEach(btn => {
    btn.addEventListener('click', () => {
      selectedMat = nameToId[btn.dataset.mat];
      matButtons.forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
    });
  });

  document.getElementById('clear').addEventListener('click', () => {
    grid.fill(EMPTY);
    render();
  });

  function paint(clientX, clientY){
    const rect = canvas.getBoundingClientRect();
    const scaleX = W / rect.width;
    const scaleY = H / rect.height;
    const cx = (clientX - rect.left) * scaleX;
    const cy = (clientY - rect.top) * scaleY;
    const ix = Math.floor(cx);
    const iy = Math.floor(cy);
    const r = 2;
    for(let dy = -r; dy <= r; dy++){
      for(let dx = -r; dx <= r; dx++){
        if(dx * dx + dy * dy <= r * r + 1){
          const x = ix + dx, y = iy + dy;
          if(inBounds(x, y)) grid[I(x, y)] = selectedMat;
        }
      }
    }
    render();
  }

  canvas.addEventListener('mousedown', e => { drawing = true; paint(e.clientX, e.clientY); });
  window.addEventListener('mouseup', () => drawing = false);
  canvas.addEventListener('mousemove', e => { if(drawing) paint(e.clientX, e.clientY); });
  canvas.addEventListener('touchstart', e => { drawing = true; paint(e.touches[0].clientX, e.touches[0].clientY); e.preventDefault(); }, {passive: false});
  canvas.addEventListener('touchmove', e => { if(drawing) paint(e.touches[0].clientX, e.touches[0].clientY); e.preventDefault(); }, {passive: false});
  window.addEventListener('touchend', () => drawing = false);
  canvas.addEventListener('contextmenu', e => e.preventDefault());

  function loop(){
    step();
    render();
    requestAnimationFrame(loop);
  }
  loop();

  window.sim = {
    w: W,
    h: H,
    tick(n){
      const steps = Math.max(0, Math.floor(n));
      for(let i = 0; i < steps; i++) step();
      render();
    },
    get(x, y){
      if(!inBounds(x, y)) return undefined;
      return names[grid[I(x, y)]];
    },
    set(x, y, material){
      if(!inBounds(x, y)) return;
      const id = nameToId[material];
      if(id !== undefined){
        grid[I(x, y)] = id;
        render();
      }
    },
    clear(){
      grid.fill(EMPTY);
      render();
    }
  };
})();
</script>
</body>
</html>
